// Function to set a cookie
function setCookie(name, value, days) {
    const date = new Date();
    date.setTime(date.getTime() + (days * 24 * 60 * 60 * 1000));
    const expires = "expires=" + date.toUTCString();
    document.cookie = name + "=" + encodeURIComponent(value) + ";" + expires + ";path=/";
}

// Function to get a cookie
function getCookie(name) {
    const nameEQ = name + "=";
    const ca = document.cookie.split(';');
    for(let i = 0; i < ca.length; i++) {
        let c = ca[i];
        while (c.charAt(0) === ' ') c = c.substring(1, c.length);
        if (c.indexOf(nameEQ) === 0) return decodeURIComponent(c.substring(nameEQ.length, c.length));
    }
    return null;
}

// Function to handle login
function login(username, password, rememberMe) {
    // Simulate password hashing
    const passwordHash = btoa(password); // Using base64 for simplicity

    if (rememberMe) {
        setCookie('rememberMe', JSON.stringify({ username, passwordHash }), 30);
    }

    // Actual login implementation would happen here
}

// Auto-login using cookie if available
